4. {
5.     public decimal CalculateTotal(decimal unitPrice, int quantity, decimal taxRate)
6.     {
7.         if (quantity < 0)
8.             throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity cannot be negative.");
9.         if (unitPrice < 0)
10.             throw new ArgumentOutOfRangeException(nameof(unitPrice), "Unit price cannot be negative.");
