using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service = new();

    // --- CreateOrder: success paths ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 5m, Quantity = 3 },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(35m, order.Total); // 10*2 + 5*3
        Assert.AreEqual(2, order.Items.Count);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Book", Price = 19.99m, Quantity = 1 },
        };

        // Act
        var order = _service.CreateOrder("cust-2", items);

        // Assert
        Assert.AreEqual(19.99m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Clock", Price = 25m, Quantity = 1 },
        };
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("cust-3", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    // --- CreateOrder: failure paths ---

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = 1m, Quantity = 1 },
        };

        // Act & Assert
        Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        Assert.ThrowsExactly<InvalidOperationException>(() => _service.CreateOrder("cust-1", items));
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
